class ChatbotService:
    DISCLOSURE_MESSAGE = (
        "You are chatting with an AI assistant. "
        "Type 'human' at any time to speak with a person."
    )

    def start_conversation(self, user_id: str) -> dict:
        return {
            "type": "disclosure",
            "message": self.DISCLOSURE_MESSAGE,
            "user_acknowledged": False,
        }

    def process_message(self, user_id: str, message: str) -> dict:
        if message.lower() == "human":
            return self._escalate_to_human(user_id)
        return self._generate_response(message)

from dataclasses import dataclass from datetime import datetime
@dataclass class CandidateEvaluation: candidate_id: str score: float confidence: float explanation: str bias_metrics: dict human_review_required: bool timestamp: datetime
class ResumeScreener: def evaluate(self, resume: dict, job_req: dict) -> CandidateEvaluation: self.logger.log_input(resume, job_req) # Article 12 risk = self.risk_manager.assess(resume) # Article 9 if risk.requires_intervention: return self._flag_for_human_review(resume, risk)
score, features, confidence = self._score_resume(resume, job_req) bias = self.bias_detector.analyze( # Article 10 score=score, features=features, protected_attributes=["gender", "age", "ethnicity"], ) human_review = confidence < 0.7 or bias["disparity_score"] > 0.1 # Art 14 explanation = self._generate_explanation(features) # Art 13
eval_ = CandidateEvaluation( candidate_id=resume["id"], score=score, confidence=confidence, explanation=explanation, bias_metrics=bias, human_review_required=human_review, timestamp=datetime.utcnow(), ) self.logger.log_output(eval_) return eval_

class SyntheticContentLabeler:
    def label_image(self, image, metadata: dict):
        return self._add_c2pa_manifest(image, {
            "ai_generated": True,
            "generator": metadata.get("model"),
            "timestamp": datetime.utcnow().isoformat(),
            "organization": metadata.get("org"),
        })

    def label_text(self, text: str, metadata: dict) -> dict:
        import hashlib
        return {
            "content": text,
            "metadata": {
                "ai_generated": True,
                "model": metadata.get("model"),
                "timestamp": datetime.utcnow().isoformat(),
                "hash": hashlib.sha256(text.encode()).hexdigest(),
            },
        }
